 local ReplicatedStorage = game:GetService("ReplicatedStorage") local Players = game:GetService("Players") local TweenService = game:GetService("TweenService") local Debris = game:GetService("Debris") local PlayerTitleDisplayEvent = ReplicatedStorage:WaitForChild("PlayerTitleDisplayEvent") local ShowBrainrotOnJLoEvent = ReplicatedStorage:WaitForChild("ShowBrainrotOnJLoEvent") local BrainrotDefinitions = require(ReplicatedStorage:WaitForChild("BrainrotDefinitions")) local vfxFolder = ReplicatedStorage:WaitForChild("BrainrotVFX") local player = Players.LocalPlayer local playerTitles = {} local currentEffects = {} local titleCleanupQueue = {} local effectCleanupQueue = {} local TITLE_LIFETIME = 300 local CLEANUP_INTERVAL = 30 local MAX_TITLES_PER_PLAYER = 3 local function scheduleCleanup(targetTable, key, delay) spawn(function() wait(delay or CLEANUP_INTERVAL) if targetTable[key] then if targetTable[key].gui then pcall(function() targetTable[key].gui:Destroy() end) end targetTable[key] = nil end end) end local function selectiveClearTitles(character, keepGUI) if not character or not character.Parent then return end local titlesToRemove = {} for _, child in pairs(character:GetChildren()) do if child:IsA("BillboardGui") then local name = child.Name:lower() if name:find("title") or name:find("brainrot") or name:find("billboard") then if keepGUI and child == keepGUI then print("?? KEEPING: " .. child.Name) else table.insert(titlesToRemove, child) end end end end for _, gui in ipairs(titlesToRemove) do pcall(function() gui:Destroy() end) print("??? SELECTIVE: Removed " .. gui.Name) end local head = character:FindFirstChild("Head") if head then for _, child in pairs(head:GetChildren()) do if child:IsA("BillboardGui") then if keepGUI and child == keepGUI then print("?? KEEPING head billboard") else pcall(function() child:Destroy() end) print("??? SELECTIVE: Removed head billboard") end end end end end local function playBrainrotEffects(character, brainrotName) if not characte