= part local alignOri = Instance.new("AlignOrientation") alignOri.Attachment0 = partAttachment alignOri.Attachment1 = rootAttachment alignOri.RigidityEnabled = true alignOri.MaxTorque = 1e6 alignOri.Responsiveness = 200 alignOri.Parent = part if part.Name:match("Floor") then part.Position = rootPart.Position + Vector3.new(0, 0.1, 0) local weld = Instance.new("Weld") weld.Part0 = rootPart weld.Part1 = part weld.C0 = CFrame.new(0, 0.1, 0) weld.Parent = part alignPos:Destroy() alignOri:Destroy() end if part:GetAttribute("IsVFXPart") then part.Transparency = 1 end end end for _, obj in ipairs(newVFX:GetDescendants()) do if obj:IsA("ParticleEmitter") then print("?? Enabling particle emitter:", obj.Name) obj.Enabled = true elseif obj:IsA("Motor6D") then print("?? Found Motor6D:", obj.Name) end end table.insert(currentEffects[character], { vfxModel = newVFX, rootAttachment = rootAttachment, startTime = tick() }) print("? VFX setup complete") return true end) if not success then warn("? VFX setup failed:", result) end else warn("? VFX template not found:", brainrot.vfxAsset) end end if brainrot.effects and brainrot.effects.animationId then local success, result = pcall(function() local animation = Instance.new("Animation") animation.AnimationId = brainrot.effects.animationId local animTrack = humanoid:LoadAnimation(animation) animTrack:Play() table.insert(currentEffects[character], { animTrack = animTrack, startTime = tick() }) return true end) if not success then warn("? Animation setup failed:", result) end end if brainrot.effects and brainrot.effects.soundId then local success, result = pcall(function() local sound = Instance.new("Sound") sound.SoundId = brainrot.effects.soundId local baseVolume = brainrot.effects.soundVolume or 0.5 sound:SetAttribute("BaseVolume", baseVolume) sound:SetAttribute("IsBrainrotSound", true) sound.Volume = baseVolume * (_G.BrainrotSFXVolume or 0.5) sound.Parent = rootPart sound:Play() table.insert(currentEffects[character], { sound = sound, startTime = tick() }) return true end) if not success then warn("? Sound setup failed:", result) end end end local function displayPlayerTitle(identifier, brainrotName, brainrotOdds, brainrotColor) print("?? ENHANCED: Received title for identifier:", identifier, "brainrot:", brainrotName) local character = nil local isJLo = false local targetPlayer = Players:GetPlayerByUserId(tonumber(identifier) or 0) if targetPlayer then character = targetPlayer.Character if not character then print("? Waiting for character...") spawn(function() character = targetPlayer.CharacterAdded:Wait() if character then displayPlayerTitle(identifier, brainrotName, brainrotOdds, brainrotColor) end end) return end else character = game.Workspace:FindFirstChild("JLo", true) if character then isJLo = true end end if not character then warn("? No character found for identifier:", identifier) return end if brainrotName then spawn(function() playBrainrotEffects(character, brainrotName) end) end local oldGUI = nil if playerTitles[identifier] and playerTitles[identifier].gui then oldGUI = playerTitles[identifier].gui end playerTitles[identifier] = nil if not brainrotName then selectiveClearTitles(character) print("??? CLEARED title for identifier: " .. identifier) return end local head = character:FindFirstChild("Head") or character:FindFirstChildWhichIsA("BasePart") if not head then warn("? No head found for character") return end local uniqueName = "PERMANENT_PlayerTitle_" .. identifier .. "_" .. tick() local billboard = Instance.new("BillboardGui") billboard.Name = uniqueName billboard.Adornee = head billboard.Size = UDim2.new(0, 300, 0, 80) billboard.StudsOffset = Vector3.new(0, 3.5, 0) billboard.AlwaysOnTop = true billboard.MaxDistance = 100 billboard.Parent = character local titleLabel = Instance.new("TextLabel") titleLabel.Size = UDim2.new(1, 0, 1, 0) titleLabel.Position = UDim2.new(0, 0, 0, 0) titleLabel.BackgroundTransparency = 1 titleLabel.Font = Enum.Font.Arcade titleLabel.Text = string.for