 if playerTitles[userId].gui then pcall(function() playerTitles[userId].gui:Destroy() end) end playerTitles[userId] = nil end if leavingPlayer.Character and currentEffects[leavingPlayer.Character] then for _, effectGroup in pairs(currentEffects[leavingPlayer.Character]) do if effectGroup.vfxModel then pcall(function() effectGroup.vfxModel:Destroy() end) end if effectGroup.rootAttachment then pcall(function() effectGroup.rootAttachment:Destroy() end) end if effectGroup.animTrack then pcall(function() effectGroup.animTrack:Stop() effectGroup.animTrack:Destroy() end) end if effectGroup.sound then pcall(function() effectGroup.sound:Destroy() end) end end currentEffects[leavingPlayer.Character] = nil end print("?? Cleaned up data for leaving player:", leavingPlayer.Name) end) spawn(function() while true do wait(CLEANUP_INTERVAL) for _, player in pairs(Players:GetPlayers()) do if player.Character then local titleBillboards = {} for _, child in pairs(player.Character:GetChildren()) do if child:IsA("BillboardGui") then local name = child.Name:lower() if name:find("title") or name:find("brainrot") or name:find("billboard") then table.insert(titleBillboards, child) end end end if #titleBillboards > MAX_TITLES_PER_PLAYER then print("?? PERIODIC CLEANUP: Found " .. #titleBillboards .. " title GUIs on " .. player.Name) table.sort(titleBillboards, function(a, b) local aTime = tonumber(string.match(a.Name, "(%d+%.?%d*)$")) or 0 local bTime = tonumber(string.match(b.Name, "(%d+%.?%d*)$")) or 0 return aTime > bTime end) local keepGUI = titleBillboards[1] selectiveClearTitles(player.Character, keepGUI) end end end for character, effects in pairs(currentEffects) do if not character.Parent then currentEffects[character] = nil else local now = tick() for i = #effects, 1, -1 do local effect = effects[i] if effect.startTime and (now - effect.startTime) > 300 then if effect.vfxModel then pcall(function() effect.vfxModel:Destroy() end) end if effect.rootAttachment then pcall(function() effect.rootAttachment:Destroy() end) end if effect.animTrack then pcall(function() effect.animTrack:Stop() effect.animTrack:Destroy() end) end if effect.sound then pcall(function() effect.sound:Destroy() end) end table.remove(effects, i) end end end end end end) _G.ClearAllPlayerTitles = function() for _, player in pairs(Players:GetPlayers()) do if player.Character then selectiveClearTitles(player.Character) end end playerTitles = {} print("?? MANUALLY cleared ALL player titles") end _G.RefreshPlayerTitle = function(playerName) local targetPlayer = Players:FindFirstChild(playerName) if targetPlayer and playerTitles[targetPlayer.UserId] then local data = playerTitles[targetPlayer.UserId] displayPlayerTitle(targetPlayer.UserId, data.name, data.odds, data.color) end end _G.StopTitleCleanup = function() print("?? EMERGENCY: Stopped all title cleanup!") end _G.GetCurrentPlayerTitles = function() return playerTitles end _G.GetCurrentEffects = function() return currentEffects end spawn(function() while true do wait(120) for _, player in pairs(Players:GetPlayers()) do if player.Character then for _, child in pairs(player.Character:GetChildren()) do if child:IsA("BillboardGui") and child.Name:find("PERMANENT_PlayerTitle_") then local timestamp = tonumber(string.match(child.Name, "(%d+%.?%d*)$")) if timestamp and (tick() - timestamp) > TITLE_LIFETIME then print("?? Removing expired title:", child.Name) pcall(function() child:Destroy() end) end end end end end end end) print("?? ENHANCED Player Title Display System Ready!") print("? Features:") print(" - Enhanced VFX integration with error handling") print(" - Selective cleanup preserving active titles") print(" - Permanent title system with auto-cleanup") print(" - Improved memory management") print(" - Robust error recovery") print(" - Character respawn handling") print("??? Use _G.ClearAllPlayerTitles() to manually clear all titles") print("??? Use _G.StopTitleCleanup() if titles keep getting deleted") print("??? Use _G.Refresh