rningText") if show then blackFrame.Visible = true local warningSound = Instance.new("Sound") warningSound.SoundId = "rbxasset://sounds/electronicpingshort.wav" warningSound.Volume = 0.5 warningSound.Parent = SoundService warningSound:Play() warningSound.Ended:Connect(function() warningSound:Destroy() end) local fadeInTween = TweenService:Create(blackFrame, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundTransparency = 0} ) fadeInTween:Play() local textFadeTween = TweenService:Create(warningText, TweenInfo.new(0.5, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {TextTransparency = 0} ) textFadeTween:Play() else local fadeOutTween = TweenService:Create(blackFrame, TweenInfo.new(0.4, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundTransparency = 1} ) local textFadeOutTween = TweenService:Create(warningText, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {TextTransparency = 1} ) fadeOutTween:Play() textFadeOutTween:Play() fadeOutTween.Completed:Connect(function() blackFrame.Visible = false end) end end ShowBlackScreenEvent.OnClientEvent:Connect(function(show) toggleBlackScreen(show) end) createBlackScreenGui() print("??? Safety Net Client Ready!")

