ow then indicator.Visible = true statusLabel.Text = "?? COMBAT ZONE ??" statusLabel.TextColor3 = Color3.fromRGB(100, 255, 100) local pulseTween = TweenService:Create(statusLabel, TweenInfo.new(1.5, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut, -1, true), {TextTransparency = 0.3} ) pulseTween:Play() else indicator.Visible = false end end CombatZoneStatusEvent.OnClientEvent:Connect(function(newInCombatZone) inCombatZone = newInCombatZone updateCombatZoneDisplay(inCombatZone) end) _G.IsInCombatZone = function() return inCombatZone end _G.CanDealDamage = function() return inCombatZone end createCombatZoneIndicator() print("?? Clean Combat Zone System Ready - Damage Control Only!")

